const items = $input.all();
items.push({
  json: {
    id: "1FwytkqzbHMaqlsYOEA7h0m9twKlW5q15",
    name: "Ra├¡z"
  }
});
return items;

const items = $input.all();
// Usamos el contexto de ejecuci├│n para obtener el ID de la carpeta que se estaba procesando
// Esto es mucho m├ís seguro que confiar en la metadata del archivo
return items.map((item, index) => ({
  json: {
    ...item.json,
    // Recuperamos el ID del nodo que aliment├│ la b├║squeda
    parent_id: $('Agregar Raiz').item.json.id
  },
  pairedItem: { item: index }
}));

const items = $input.all();
let contexto = '';
let images = [];
let sourceUrl = '';
let huntPage = '';

for (const item of items) {
  const res = item.json;
  if (res.type === 'text') {
    contexto += `[Contexto Documento]: ${res.content}\n\n`;
    if (!huntPage && res.metadata && res.metadata.page_number) {
      huntPage = res.metadata.page_number;
    }
  } else if (res.type === 'image' && res.metadata && res.metadata.original_content) {
    images.push(res.metadata.original_content);
  }
  if (!sourceUrl && res.metadata && res.metadata.source_url) {
    sourceUrl = res.metadata.source_url;
  }
}

return [{
  json: {
    contexto,
    imagesBase64: images,
    sourceUrl: sourceUrl || 'https://learn.zohopublic.com',
    huntPage,
    needsImageHunt: images.length === 0 && !!sourceUrl && !!huntPage,
    pregunta: $('input').item.json.pregunta,
    chat_id: $('input').item.json.chat_id
  }
}];

const previous = $('Analizar Resultados (JS)').first().json;
const items = $input.all();

let allImages = [...(previous.imagesBase64 || [])];

for (const item of items) {
  const fetchedData = item.json;
  if (fetchedData && fetchedData.metadata && fetchedData.metadata.original_content) {
    allImages.push(fetchedData.metadata.original_content);
  }
}

return [{
  json: {
    ...previous,
    imagesBase64: allImages
  }
}];

const data = $input.item.json;
let promptParts = [
  {
    text: `Contexto extra├¡do de Zoho:\n${data.contexto}\n\nPregunta del operario:\n${data.pregunta}\n\nInstrucci├│n:\nEres un asistente experto t├®cnico de Satcom. Responde a la pregunta usando SOLO la informaci├│n del contexto. Te he pasado im├ígenes indexadas (algunas pueden ser logos irrelevantes o banners). Usa SOLO la(s) imagen(es) relevante(s) (ej. diagramas o capturas de proceso) para razonar tu respuesta.\n\nMUY IMPORTANTE: Para que el usuario pueda ver las im├ígenes clave a las que te refieres, DEBES escribir al final absoluto de tu respuesta exactamente el tag: [ENVIAR_IMAGENES: X, Y] indicando el n├║mero o n├║meros de las im├ígenes que resultaron ├║tiles (ej. [ENVIAR_IMAGENES: 1] o [ENVIAR_IMAGENES: 1, 2]). Si ninguna imagen es ├║til o son puros logos, no escribas la etiqueta.`
  }
];

const images = data.imagesBase64 || [];
for (let i = 0; i < images.length; i++) {
  if (images[i]) {
    promptParts.push({ text: `\n--- [Imagen ${i}] ---` });
    promptParts.push({
      inlineData: {
        mimeType: 'image/jpeg',
        data: images[i]
      }
    });
  }
}

// FIX URL TRUNCADA POR EL PARSER PDF
let finalUrl = data.sourceUrl;
if (finalUrl && finalUrl.endsWith('?')) {
  const paramMatch = data.contexto.match(/p=[a-f0-9]{30,}/i);
  if (paramMatch) {
    finalUrl += paramMatch[0];
  }
}

return [{
  json: {
    source_url: finalUrl,
    chat_id: data.chat_id,
    all_images: images,
    gemini_body: {
      contents: [{ parts: promptParts }]
    }
  }
}];

// El nodo Telegram sobrescribe el JSON de entrada con su propia API response.
// Por lo tanto, saltamos hacia atras visualmente y copiamos el texto directo.
const textoFinal = $('Procesar Output Gemini (JS)').first().json.final_response;

return [{
  json: {
    response: textoFinal || "Sin respuesta"
  }
}];

const geminiResponse = $input.item.json.candidates[0].content.parts[0].text;
const preparador = $('Preparar Body LLM (JS)').first().json;
const all_images = preparador.all_images || [];

let finalResponse = geminiResponse;
let indexesToSend = [];

// Parse [ENVIAR_IMAGENES: 1, 2]
const regex = /\[ENVIAR_IMAGENES:\s*([\d,\s]+)\]/i;
const match = finalResponse.match(regex);

if (match) {
  let indices = match[1].split(',').map(s => parseInt(s.trim())).filter(n => !isNaN(n));
  indexesToSend = indices;
  // Limpiar el tag del texto final
  finalResponse = finalResponse.replace(regex, '').trim();
}

const finalResponseConEnlace = `${finalResponse}\n\n­ƒöù [Ver en el Manual Original](${preparador.source_url})`;

let outputItems = [];

// Quitar duplicados por si Gemini repite indices
indexesToSend = [...new Set(indexesToSend)];

if (indexesToSend.length > 0) {
  for (let idx of indexesToSend) {
    if (all_images[idx]) {
      outputItems.push({
        json: {
          chat_id: preparador.chat_id,
          final_response: finalResponseConEnlace,
          send_image: true,
          image_idx: idx
        },
        binary: {
          data: {
            data: all_images[idx],
            mimeType: 'image/jpeg',
            fileName: `imagen_${idx}.jpg`
          }
        }
      });
    }
  }
}

if (outputItems.length === 0) {
  // Sin imagenes que enviar
  outputItems.push({
    json: {
      chat_id: preparador.chat_id,
      final_response: finalResponseConEnlace,
      send_image: false
    }
  });
}

return outputItems;

// Obtenemos los items que vienen del nodo anterior (el de Gemini)
const items = $input.all();

// Creamos un nuevo arreglo con la informaci├│n extra├¡da
return items.map(item => {
  const metadata = item.json.usageMetadata || {};

  return {
    json: {
      modelo: item.json.modelVersion,
      tokens_entrada: metadata.promptTokenCount || 0,
      tokens_salida: metadata.candidatesTokenCount || 0,
      tokens_pensamiento: metadata.thoughtsTokenCount || 0, // Nuevo en modelos como Gemini 2.0 Thinking
      tokens_totales: metadata.totalTokenCount || 0,
      id_respuesta: item.json.responseId
    }
  };
});

return {
  Chat : $input.first().json.ChatTxt,
  NuevaRespuesta : $('Input').first().json.MensajeTexto 
};

