/* Tratamiento de datos para Gemini */
const rawData = $json.result || $json.error || $json;

if (Array.isArray(rawData)) {
  return rawData.map(ticket => ({
    ticketNumber: ticket.ticketNumber,
    subject: ticket.subject,
    status: ticket.status,
    createdTime: ticket.createdTime,
    contactName: ticket.contact?.fullName
  }));
}

if (typeof rawData === 'object' && rawData !== null) {
  const clean = { ...rawData };
  delete clean.orgId;
  delete clean.id;
  return clean;
}

return { result: rawData };

const searchText = $('Telegram Trigger').item.json.message.text.toLowerCase();
const accounts = items[0].json.data || [];

// Filtrar por nombre (texto parcial case-insensitive)
const filtered = accounts.filter(account => {
  const nameObj = account.Account_Name;
  const name = (typeof nameObj === 'object' && nameObj !== null) ? nameObj.name : nameObj;
  return name && name.toLowerCase().includes(searchText);
}).map(account => {
    // Normalizar datos para uso posterior
    const nameObj = account.Account_Name;
    return {
        ...account,
        account_name: (typeof nameObj === 'object' && nameObj !== null) ? nameObj.name : nameObj,
        account_id: (typeof nameObj === 'object' && nameObj !== null) ? nameObj.id : account.id
    };
});

// Devolver estructura agregada para Switch
return [{
    json: {
        matches: filtered,
        count: filtered.length
    }
}];

