// 0. Safe Input Parsing
let input = query;
if (typeof query === 'string') {
    try {
            if (query.trim().startsWith('{')) {
                input = JSON.parse(query);
            } else {
                input = { ticket_number: query };
            }
    } catch (e) {
        input = { ticket_number: query };
    }
}
const ticketNum = input.ticket_number || input;

let accessToken = '';
const apiDomain = 'https://desk.zoho.com';

// 1. Refresh Token Step
try {
    const tokenResponse = await this.helpers.httpRequest({
        url: 'https://accounts.zoho.com/oauth/v2/token',
        method: 'POST',
        headers: {
            'Content-Type': 'application/x-www-form-urlencoded'
        },
        body: {
            refresh_token: refreshToken,
            client_id: clientId,
            client_secret: clientSecret,
            grant_type: 'refresh_token'
        },
        json: true
    });

    if (!tokenResponse.access_token) {
        return JSON.stringify({ error: 'Token Refresh Missing Access Token', details: tokenResponse });
    }
    accessToken = tokenResponse.access_token;
} catch (tokenError) {
    const errBody = tokenError.response ? tokenError.response.data : tokenError.message;
    return JSON.stringify({ 
        error: 'CRITICAL: Token Refresh Failed',
        step: 'accounts.zoho.com',
        statusCode: tokenError.response ? tokenError.response.status : 'Unknown',
        details: errBody
    });
}

// 2. API Call Step
try {
    const response = await this.helpers.httpRequest({
        url: `${apiDomain}/api/v1/tickets/search`,
        method: 'GET',
        headers: {
            'Authorization': `Zoho-oauthtoken ${accessToken}`,
            'orgId': orgId,
            'User-Agent': 'python-requests/2.31.0',
            'Accept': '*/*'
        },
        qs: { ticketNumber: ticketNum },
        json: true
    });

    if (response.data && response.data.length > 0) {
        return JSON.stringify({
            found: true,
            id: response.data[0].id,
            status: response.data[0].status,
            subject: response.data[0].subject
        });
    }
    return JSON.stringify({ found: false, message: 'Ticket not found' });
} catch (apiError) {
    const errBody = apiError.response ? apiError.response.data : apiError.message;
    return JSON.stringify({ 
        error: 'API Search Failed (But Token OK)',
        step: 'desk.zoho.com',
        usedDomain: apiDomain,
        statusCode: apiError.response ? apiError.response.status : 'Unknown',
        details: errBody
    });
}

