const initialResults = filterData.originalResults || [];
const relevantResults = filterData.relevantResults || [];
const input = $('Extraer Plan').item.json;

// Chunks adyacentes
let adjacentChunks = [];
try {
  adjacentChunks = $input.all()
    .map(i => i.json)
    .filter(r => r && r.id);
} catch (_) { adjacentChunks = []; }

if (initialResults.length === 0 && adjacentChunks.length === 0) {
  return [{ json: {
    contexto: '', images: [], sourceUrl: '',
    sinResultados: true, queries: input.queries || [], ...input
  } }];
}

// --- Deduplicar por contenido ---
const seenContent = new Set();
const dedup = (arr) => arr.filter(r => {
  const key = (r.content || '').trim();
  if (!key || seenContent.has(key)) return false;
  seenContent.add(key);
  return true;
});

const dedupedInitial = dedup(initialResults);
const dedupedAdjacent = dedup(adjacentChunks);

// --- Separar texto e im├ígenes ---
const textResults = dedupedInitial.filter(r => r.type === 'text');
const imageResults = dedupedInitial.filter(r => r.type === 'image');

// --- Agrupar por source_url ÔåÆ capturar groupMeta V4 ---
const allTextChunks = [
  ...textResults,
  ...dedupedAdjacent.filter(r => r.type === 'text')
];

const grouped = {};
const groupMeta = {}; // metadata V4: manual_name, article_title, contextual_header

for (const chunk of allTextChunks) {
  const src = chunk.metadata?.source_url || chunk.source_url || 'unknown';
  const pn = chunk.metadata?.page_number || chunk.page_number || 0;
  const ci = chunk.metadata?.chunk_index || chunk.chunk_index || 0;
  if (!grouped[src]) {
    grouped[src] = [];
    groupMeta[src] = {
      manual_name: chunk.metadata?.manual_name || '',
      article_title: chunk.metadata?.article_title || '',
      contextual_header: chunk.metadata?.contextual_header || ''
    };
  }
  grouped[src].push({ content: chunk.content, _pn: pn, _ci: ci });
}

// Ordenar chunks y construir contexto con header V4
const contextParts = [];
for (const [src, chunks] of Object.entries(grouped)) {
  chunks.sort((a, b) => a._pn - b._pn || a._ci - b._ci);
  const meta = groupMeta[src];
  const headerParts = [meta.manual_name, meta.article_title, meta.contextual_header].filter(Boolean);
  const headerLine = headerParts.length > 0
    ? '[' + headerParts.join(' ÔÇ║ ') + ']\n'
    : '';
  contextParts.push(headerLine + chunks.map(c => c.content).join('\n'));
}

const contexto = contextParts.join('\n\n---\n\n');

// Im├ígenes del manual
