  imageUrl: r.metadata?.image_url || null,
  base64: r.metadata?.original_content || null,
  sourceUrl: r.metadata?.source_url || ''
})).slice(0, 4);

const mainSourceUrl = relevantResults[0]?.metadata?.source_url
  || initialResults[0]?.metadata?.source_url || '';

return [{ json: {
