for (let key in payloadZoho) {
    if (payloadZoho[key] === "" || payloadZoho[key] === null || payloadZoho[key] === undefined) {
        delete payloadZoho[key];
    }
}

// 4. ENV├ìO DE CREACI├ôN A ZOHO
