if (!candidates || candidates.length === 0) {
  const prep = $('Preparar Body LLM (JS)').first().json;
  return [{ json: { chat_id: prep.chat_id, final_response: 'Lo siento, no pude procesar tu consulta. Por favor intenta de nuevo.', send_image: false } }];
}

const geminiResponse = candidates[0].content.parts[0].text;
const preparador = $('Preparar Body LLM (JS)').first().json;
const all_images = preparador.all_images || [];

let finalResponse = geminiResponse;
let imageToSend = null;

const regex = /\[ENVIAR_IMAGENES:\s*([\d,\s]+)\]/i;
const match = finalResponse.match(regex);

if (match) {
  const indices = match[1].split(',').map(s => parseInt(s.trim())).filter(n => !isNaN(n));
  for (const idx of indices) {
    if (all_images[idx]) {
      imageToSend = all_images[idx];
      break;
    }
  }
  finalResponse = finalResponse.replace(regex, '').trim();
}

let finalUrl = preparador.source_url;
if (finalUrl && finalUrl.endsWith('?')) {
  const paramMatch = (preparador.contexto || '').match(/p=[a-f0-9]{30,}/i);
  if (paramMatch) finalUrl += paramMatch[0];
}

const finalResponseConEnlace = `${finalResponse}\n\n­ƒöù [Ver en el Manual Original](${finalUrl})`;

const output = {
  json: {
    chat_id: preparador.chat_id,
    final_response: finalResponseConEnlace,
    send_image: !!imageToSend
  }
};

if (imageToSend) {
  output.binary = {
    data: {
      data: imageToSend,
      mimeType: 'image/jpeg',
      fileName: 'imagen.jpg'
    }
  };
}

return [output];

const data = $input.item.json;
