  {
    text: `Contexto extra├¡do de Zoho:\n${data.contexto}\n\nPregunta del operario:\n${data.pregunta}\n\nInstrucci├│n:\nEres un asistente experto t├®cnico de Satcom. Responde a la pregunta usando SOLO la informaci├│n del contexto. Te he pasado im├ígenes indexadas (algunas pueden ser logos irrelevantes o banners). Usa SOLO la(s) imagen(es) relevante(s) (ej. diagramas o capturas de proceso) para razonar tu respuesta.\n\nMUY IMPORTANTE: Para que el usuario pueda ver las im├ígenes clave a las que te refieres, DEBES escribir al final absoluto de tu respuesta exactamente el tag: [ENVIAR_IMAGENES: X, Y] indicando el n├║mero o n├║meros de las im├ígenes que resultaron ├║tiles (ej. [ENVIAR_IMAGENES: 1] o [ENVIAR_IMAGENES: 1, 2]). Si ninguna imagen es ├║til o son puros logos, no escribas la etiqueta.`
  }
];

const images = data.imagesBase64 || [];
for (let i = 0; i < images.length; i++) {
  if (images[i]) {
    promptParts.push({ text: `\n--- [Imagen ${i}] ---` });
    promptParts.push({ inlineData: { mimeType: 'image/jpeg', data: images[i] } });
  }
}

let finalUrl = data.sourceUrl;
if (finalUrl && finalUrl.endsWith('?')) {
  const paramMatch = data.contexto.match(/p=[a-f0-9]{30,}/i);
  if (paramMatch) finalUrl += paramMatch[0];
}

return [{
  json: {
    source_url: finalUrl,
    contexto: data.contexto,
    chat_id: data.chat_id,
    all_images: images,
    gemini_body: {
      contents: [{ parts: promptParts }]
    }
  }
}];

const analyzed = $('Analizar Resultados (JS)').first().json;
const fetchedItems = $input.all();

let allImages = [...(analyzed.imagesFromVector || [])];

for (const item of fetchedItems) {
  const d = item.json;
  if (d?.metadata?.original_content) {
    allImages.push(d.metadata.original_content);
  }
}

const seen = new Set();
allImages = allImages.filter(img => {
  const key = img.substring(0, 80);
  if (seen.has(key)) return false;
  seen.add(key);
