const items = $input.all();
let contexto = '';
let textCount = 0;
let images = [];
let sourceUrl = '';

for (const item of items) {
  const res = item.json;
  if (res.type === 'text' && textCount < 7) {
    contexto += `[Contexto Documento]: ${res.content}\n\n`;
    textCount++;
  } else if (res.type === 'image' && res.metadata?.original_content) {
    images.push(res.metadata.original_content);
  }
  if (!sourceUrl && res.metadata?.source_url) {
    sourceUrl = res.metadata.source_url;
  }
}

return [{
  json: {
    contexto,
    imagesFromVector: images,
    sourceUrl,
    pregunta: $('input').item.json.pregunta,
    chat_id: $('input').item.json.chat_id
  }
}];

const results = $input.all().map(i => i.json).filter(r => r && r.id);
const meaningful = results.filter(r => (r.content || '').trim().length >= 40);

// Enviamos el top 8 para reranking
const candidates = meaningful
  .sort((a, b) => (b.combined_score || 0) - (a.combined_score || 0))
  .slice(0, 8);

const formatted = candidates.map((c, i) => `[FRAGMENTO #${i}]\n${c.content}`).join('\n\n');

return [{ json: { 
  query: $('Extraer_Plan').item.json.querySearch || $('input').item.json.query,
  candidates_text: formatted,
  candidates_raw: candidates,
  all_results: results
} }];

const inputData = $('Filtrar_Candidatos').item.json;
const candidates = inputData.candidates_raw;
const allResults = inputData.all_results;

try {
  // CORRECCI├ôN: Leer de $json.output que es donde el AI Agent entrega el texto
  const cleanText = $json.output || '';
  const data = JSON.parse(cleanText);
  const selectedIndices = data.indices || [];

  const relevantResults = selectedIndices.map(i => candidates[i]).filter(Boolean);
  if (relevantResults.length === 0 && candidates.length > 0) {
    relevantResults.push(candidates[0]);
  }

  const seen = new Set();
  const sourceUrls = [], pageNumbers = [], excludeIds = allResults.map(r => r.id).filter(Boolean);

  for (const r of relevantResults) {
    const src = r.metadata?.source_url || '';
    const pn = r.metadata?.page_number || 0;
    const key = `${src}|${pn}`;
    if (src && !seen.has(key)) {
      seen.add(key);
      sourceUrls.push(src);
      pageNumbers.push(pn);
    }
  }

  return [{ json: {
    originalResults: allResults,
    relevantResults: relevantResults,
    indices_utilizados: selectedIndices,
    needsExpansion: sourceUrls.length > 0,
    expansionParams: {
      p_source_urls: sourceUrls,
      p_page_numbers: pageNumbers,
      p_exclude_ids: excludeIds,
      p_window: 1
    }
  } }];
} catch (e) {
  return [{ json: {
    originalResults: allResults,
    relevantResults: [candidates[0]],
    needsExpansion: !!candidates[0],
    error: e.message,
    expansionParams: {
      p_source_urls: candidates[0]?.metadata?.source_url ? [candidates[0].metadata.source_url] : [],
      p_page_numbers: candidates[0]?.metadata?.page_number ? [candidates[0].metadata.page_number] : [],
      p_exclude_ids: allResults.map(r => r.id).filter(Boolean),
      p_window: 1
    }
  } }];
}

