      return [{ json: { found: false, message: "No se proporcion├│ un n├║mero de caso para buscar." } }];
  }

  // Limpiamos la variable para que quede como numero puro "1592"
  const numeroStringBusqueda = String(numeroCrudo).replace(/\D/g,'');

  if (numeroStringBusqueda === "") {
      return [{ json: { found: false, message: "La variable no conten├¡a ning├║n d├¡gito v├ílido." } }];
  }

  while (buscarPaginas) {
    // Pedimos los tickets simples y normales a Zoho (sin filtros conflictivos)
    const urlList = `https://desk.zoho.com/api/v1/tickets?limit=${limit}&from=${fromIndex}`;

    const resList = await this.helpers.httpRequest({
      method: "GET",
      url: urlList,
      headers: {
        "Authorization": "Zoho-oauthtoken " + token,
        "orgId": orgId
      },
      json: true
    });

    let ticketsArray = [];
    if (Array.isArray(resList)) {
       ticketsArray = resList;
    } else if (resList && Array.isArray(resList.data)) {
       ticketsArray = resList.data;
    } else {
       if (fromIndex === 0) return [{ json: { found: false, message: "Respuesta de tickets vac├¡a." } }];
       break; 
    }

    if (ticketsArray.length === 0) break;

    // MAGIA JAVASCRIPT: Buscamos manualmente en esta p├ígina el ticketNumber
    // Nota: ticketNumber en Zoho a veces viene como numero entero o como string, convertimos ambos a string para asegurar
    const found = ticketsArray.find(ticket => String(ticket.ticketNumber) === numeroStringBusqueda);

    if (found) {
        // ENCONTRADO! 
        return [{ 
            json: { 
                found: true, 
                ticket: {
                    id: found.id,
                    ticketNumber: found.ticketNumber,
                    status: found.statusType, // Ej: "Open", "Closed"
                    subject: found.subject,
                    createdTime: found.createdTime,
                    contactId: found.contactId, // Por si lo necesitas para despues
                    resolution: found.resolution || "Sin resoluci├│n a├║n",
                    raw_data: found
                },
                matchMethod: "Brute Force Filter"
            } 
        }];
    }

    // Si no lo encontramos en la pagina actual, avanzamos a la siguiente
    if (ticketsArray.length < limit) {
        buscarPaginas = false;
    } else {
        fromIndex += limit;
    }
  }

  return [{ json: { found: false, message: `Revisamos todos los tickets y el caso #${numeroStringBusqueda} no existe.` } }];

} catch (error) {
  return [{ json: { found: false, error: true, message: error.message, details: error.response ? error.response.data : error } }];
}

// 1. INPUTS
const numeroCrudo = $item("0").$node["Input"].json["numero_ticket"]; 
const token = $item("0").$node["Variables"].json["TokenZoho"];
const orgId = $item("0").$node["Variables"].json["Organization_id"];

// NUEVO: Jalamos el JSON COMPLETO del nodo var_id
const datosBaseVarId = $item("0").$node["var_id"].json || {};

// El array de accountIds regulares que sacamos del usuario 
let empresasPermitidas = $item("0").$node["Variables"].json["Usuario"]["id_empresa"] || []; 
if (!Array.isArray(empresasPermitidas)) empresasPermitidas = [empresasPermitidas];

// Leemos el array VIP del nodo "Exepciones" 
let empresasVip = $item("0").$node["Exepciones"].json["Exepciones"] || [];
if (!Array.isArray(empresasVip)) empresasVip = [empresasVip];

let fromIndex = 0;
const limit = 50;
let buscarPaginas = true;

try {
  const numeroLimpio = String(numeroCrudo).replace(/\D/g,'');
  if (!numeroLimpio) return [{ json: { found: false, message: "No hay un numero de caso v├ílido." } }];

  // 2. BUSCAMOS EL TICKET PRINCIPAL CON ID (B├║squeda Inicial r├ípida)
  let ticketEncontrado = null;

  while (buscarPaginas) {
    const urlList = `https://desk.zoho.com/api/v1/tickets?limit=${limit}&from=${fromIndex}`;
    const resList = await this.helpers.httpRequest({
      method: "GET", url: urlList,
      headers: { "Authorization": "Zoho-oauthtoken " + token, "orgId": orgId },
      json: true
    });

    let ticketsArray = Array.isArray(resList) ? resList : (resList.data || []);
    if (ticketsArray.length === 0) break;

    ticketEncontrado = ticketsArray.find(t => String(t.ticketNumber) === numeroLimpio);
    if (ticketEncontrado) break;

    if (ticketsArray.length < limit) buscarPaginas = false;
    else fromIndex += limit;
  }

  // Si no existe en todo Zoho
  if (!ticketEncontrado) {
      return [{ json: { found: false, message: `El caso #${numeroLimpio} no existe.` } }];
  }

  // 3. VALIDACI├ôN DE SEGURIDAD VIP (A prueba de balas)
  const permitidasText = empresasPermitidas.map(id => String(id));
  const vipText = empresasVip.map(id => String(id));
  const ticketAccountText = String(ticketEncontrado.accountId);

  // Revisamos si ALGUNO de los IDs regulares del cliente est├í dentro de la lista VIP
  const esClienteVIP = permitidasText.some(id => vipText.includes(id));

  if (!esClienteVIP) {
      // Si NO es VIP, se aplica la ley estricta de propiedad
      if (!permitidasText.includes(ticketAccountText)) {
          return [{ 
              json: { 
                  found: false, 
                  security_blocked: true,
                  message: `El caso #${numeroLimpio} pertenece a otra empresa. Acceso denegado.`,
              } 
          }];
      }
  }

  // -------------------------------------------------------------------------
  // 4. SI PAS├ô LA SEGURIDAD, DESCARGAMOS EL "EXPEDIENTE COMPLETO"
  const headersGlobal = { "Authorization": "Zoho-oauthtoken " + token, "orgId": orgId };

  // A. RADIOGRAF├ìA DEL TICKET (Nombres reales Expandidos de cliente, empresa y agente)
  let detallesReales = ticketEncontrado; 
  let nombreCliente = "Desconocido", correoCliente = "Sin correo", nombreAgente = "Sin asignar", nombreEmpresa = "Empresa Desconocida";

  try {
      // Hacemos un llamado pidiendo expandir (include) los diccionarios internos
      const resFullTicket = await this.helpers.httpRequest({
          method: "GET", url: `https://desk.zoho.com/api/v1/tickets/${ticketEncontrado.id}?include=contacts,assignee,departments`,
          headers: headersGlobal, json: true
      });
      detallesReales = resFullTicket;

      // Ya expendidos, sacamos los nombres
      if (detallesReales.contact) {
          nombreCliente = `${detallesReales.contact.firstName || ""} ${detallesReales.contact.lastName || ""}`.trim();
          correoCliente = detallesReales.contact.email || "Sin correo";
          // Zoho mete la empresa dentro del contaco
          if (detallesReales.contact.account) {
              nombreEmpresa = detallesReales.contact.account.accountName || nombreEmpresa;
          }
      }
      if (detallesReales.assignee) {
          nombreAgente = `${detallesReales.assignee.firstName || ""} ${detallesReales.assignee.lastName || ""}`.trim();
      }
  } catch(e) { /* Nos conformamos con lo b├ísico */ }


  // B. Mensajes (Threads / Correos del caso)
  let mensajesDelCaso = [];
  let ultimoMensajeCompleto = null;

  try {
      const resThreads = await this.helpers.httpRequest({
          method: "GET", url: `https://desk.zoho.com/api/v1/tickets/${ticketEncontrado.id}/threads`,
          headers: headersGlobal, json: true
      });
      mensajesDelCaso = resThreads.data || [];

      // Extraemos y limpiamos el mensaje m├ís nuevo
      if (mensajesDelCaso.length > 0) {
          const idUltimo = mensajesDelCaso[0].id;
          try {
              const resUnicoMsj = await this.helpers.httpRequest({
                  method: "GET", url: `https://desk.zoho.com/api/v1/tickets/${ticketEncontrado.id}/threads/${idUltimo}`,
                  headers: headersGlobal, json: true
              });

              let htmlCrudo = resUnicoMsj.content || "";

              // LIMPIEZA DE HTML A TEXTO PLANO CON \n
              let textoLimpio = htmlCrudo.replace(/<br\s*[\/]?>/gi, '\n');
              textoLimpio = textoLimpio.replace(/<div[^>]*>/gi, '\n');
              textoLimpio = textoLimpio.replace(/<p[^>]*>/gi, '\n\n');
              textoLimpio = textoLimpio.replace(/<blockquote[^>]*>/gi, '\n> '); 
              textoLimpio = textoLimpio.replace(/<[^>]*>?/gm, ''); // Quita tags de dise├▒o e im├ígenes
              textoLimpio = textoLimpio.replace(/&nbsp;/g, ' ');
              textoLimpio = textoLimpio.replace(/&amp;/g, '&');
              textoLimpio = textoLimpio.replace(/&lt;/g, '<');
              textoLimpio = textoLimpio.replace(/&gt;/g, '>');
              textoLimpio = textoLimpio.replace(/&quot;/g, '"');
              textoLimpio = textoLimpio.replace(/&#39;/g, "'");

              // Aplastamos saltos horribles de linea
              textoLimpio = textoLimpio.replace(/\n\s*\n\s*\n/g, '\n\n').trim();

              ultimoMensajeCompleto = {
                  id_mensaje: idUltimo,
                  canal: resUnicoMsj.channel,
                  remitente: resUnicoMsj.fromEmailAddress || (resUnicoMsj.author ? resUnicoMsj.author.email : "Desconocido"),
                  texto_plano: textoLimpio 
              };
          } catch(e) { /* Fallback */ }
      }
  } catch(e) { mensajesDelCaso = [{ error: "No se pudieron cargar los mensajes" }]; }

  // C. Historial de Cambios (Audit History)
  let historialDelCaso = [];
  try {
      const resHistory = await this.helpers.httpRequest({
          method: "GET", url: `https://desk.zoho.com/api/v1/tickets/${ticketEncontrado.id}/history`,
          headers: headersGlobal, json: true
      });
      historialDelCaso = resHistory.data || [];
  } catch(e) { historialDelCaso = [{ error: "No se pudo cargar el historial" }]; }

  // D. Ultimos Casos de esa misma Empresa 
  let otrosCasosEmpresa = [];
  try {
      if (ticketEncontrado.accountId) {
          const resCompanyTickets = await this.helpers.httpRequest({
              method: "GET", 
              url: `https://desk.zoho.com/api/v1/accounts/${ticketEncontrado.accountId}/tickets?limit=10`,
              headers: headersGlobal, 
              json: true
          });
          otrosCasosEmpresa = resCompanyTickets.data || [];
      } else {
          otrosCasosEmpresa = [{ info: "El ticket no est├í atado a ninguna empresa." }];
      }
  } catch(e) { otrosCasosEmpresa = [{ error: "No se pudo cargar el historial de la empresa" }]; }

  // -------------------------------------------------------------------------

  // 5. ENSAMBLAMOS Y DEVOLVEMOS EL MEGA-JSON ORDENADO
  return [{ 
      json: { 
          // Bloque 1: Todo el volcado que pasaste en var_id
          ...datosBaseVarId,

          // Bloque 2: Indicadores de estado interno
          found: true,
          security_blocked: false,
          es_vip: esClienteVIP,

          // Bloque 3: Los Nombres humanos ahora s├¡ resueltos con la API
          nombres_del_ticket: { 
              agente_asignado: nombreAgente,
              nombre_empresa: nombreEmpresa,
              creador_casual: nombreCliente,
              email_creador: correoCliente
          },

          // Bloque 4: La data dura del ticket que investigamos a la perfeccion
          detalles_resolucion_zoho: {
              status: ticketEncontrado.statusType,
              subject: ticketEncontrado.subject,
              resolution: ticketEncontrado.resolution || "Sin resoluci├│n apuntada formalmente a├║n",
          },

          // Bloque 5: Anal├¡tica Profunda
          expediente_profundo: {
              ultimo_mensaje_completo: ultimoMensajeCompleto,
              mensajes_hilos_resumen: mensajesDelCaso,
              historial_auditoria: historialDelCaso,
          },
          historial_cuenta_relacionada: otrosCasosEmpresa
      } 
  }];

} catch (error) {
  return [{ json: { found: false, error: true, message: error.message } }];
}

