// Obtener Nombres
const nombres = extraccionData.nombres_del_ticket || {};
const agenteAsignadoNombre = nombres.agente_asignado || "Sin Asignar";
const clienteLlamante = nombres.creador_casual || "Desconocido";

// ==========================================
