let historialChat = "No se adjunt├│ historial previo.\n";
try {
    const mensajesDb = $items("ChatHistory").map(item => item.json);
    if (mensajesDb.length > 0) {
        historialChat = "";
        mensajesDb.forEach(item => {
            // AJUSTE: Si en PostgreSQL guardas como "role" en lugar de sender.
            const rol = item.role || item.sender || 'Usuario';
            const texto = item.content || item.message || item.text || '';
            historialChat += `*${rol}:* ${texto}\n\n`;
        });
    }
} catch (e) { 
