    } catch (error) {
        errorAtrapadoMagia = error.response ? JSON.stringify(error.response.data) : error.message;
    }
} else {
    errorAtrapadoMagia = "No se logr├│ leer el 'id_ticket' del ExtraccionDeCaso";
