// PDF Image Detector - Filesystem Compatible
const results = [];
const allItems = $input.all();

// Usamos un bucle for cl├ísico para mantener el ├¡ndice (necesario para la API interna de n8n)
for (let i = 0; i < allItems.length; i++) {
    const item = allItems[i];
    const debugInfo = { step: "start" };

    try {
        // 1. Verificamos que exista el binario
        if (!item.binary || Object.keys(item.binary).length === 0) {
            throw new Error("No binary data found");
        }

        // 2. Obtenemos la clave del binario (ej. 'data')
        const binaryKey = Object.keys(item.binary)[0];

        // 3. LEEMOS EL ARCHIVO REAL USANDO EL HELPER DE N8N
        // Esto funciona incluso si n8n usa 'filesystem-v2'
        const buffer = await this.helpers.getBinaryDataBuffer(i, binaryKey);

        // 4. Convertimos a string binaria para analizar
        const str = buffer.toString('binary');

        // 5. An├ílisis Heur├¡stico (El mismo que validamos localmente)
        const hasXObject = /\/Subtype\s*\/Image/i.test(str);
        const hasInline = /\/BI\s+/.test(str);

        debugInfo.hasImages = hasXObject || hasInline; // Esto activar├í el router
        debugInfo.stats = {
            fileSize: str.length, // Deber├¡a ser ~1.25MB ahora
            xObjects: hasXObject,
            inline: hasInline,
            pagesEst: (str.match(/\/Type\s*\/Page[^s]/g) || []).length
        };

        // 6. Retornamos el item original + metadatos
        results.push({
            json: {
                ...item.json,
                pdf_analysis: debugInfo
            },
            binary: item.binary
        });

    } catch (e) {
        debugInfo.error = e.message;
        results.push({ 
            json: { ...item.json, pdf_analysis: debugInfo }, 
            binary: item.binary 
        });
    }
}

return results;

// Analyze PDF content and detect pages with images
// This script identifies if a page is likely an image based on text density and markers
// Updated to handle n8n extractFromFile output which might flat-text the PDF

const items = $input.all();
const outputItems = [];

for (const item of items) {
  const pdfContent = item.json;
  const totalPagesReported = pdfContent.numpages || 1;
  let pages = [];

  // Try to split text by Form Feed character (\f) which is the standard PDF page separator in extracted text
  // Check both \f and potential double newlines if \f is missing but pages > 1
  let rawPageTexts = [];
  if (pdfContent.text) {
    if (pdfContent.text.includes('\f')) {
       rawPageTexts = pdfContent.text.split('\f');
    } else {
       // Fallback: If no explicit page separator found, treat as single block 
       rawPageTexts = [pdfContent.text];
    }
  } else if (Array.isArray(pdfContent.pages)) {
    rawPageTexts = pdfContent.pages.map(p => p.text || p.content || '');
  } else {
    rawPageTexts = [JSON.stringify(pdfContent)];
  }

  // Determine if we have a mismatch between detected text blocks and reported pages
  const isPaginationLost = totalPagesReported > 1 && rawPageTexts.length === 1;

  rawPageTexts.forEach((pageText, index) => {
    // If pagination is lost, we assume this text block covers Page 1 to N
    const pageNumber = isPaginationLost ? `1-${totalPagesReported}` : (index + 1);
    const trimmedText = pageText.trim();

    // IMAGE DETECTION LOGIC

    // 1. Explicit markers 
    const hasImageMarkers = /\[image\]|<img|image:|figure:|diagram:/i.test(trimmedText);

    // 2. Text density analysis 
    const textLength = trimmedText.length;
    // If pagination is lost, we expect more text. So we adjust threshold.
    const lengthThreshold = isPaginationLost ? (150 * totalPagesReported) : 150; 
    const isVeryShort = textLength < lengthThreshold; 

    // 3. Keywords that suggest visual content - RELAXED REGEX (no colon required for some)
    // "Diagrama" "Figura" often appear as titles for images
    const hasImageKeywords = /photo|picture|illustration|graphic|chart|graph|map|drawing|diagrama|esquema|figura/i.test(trimmedText);

    // 4. Low information density
    const words = trimmedText.split(/\s+/).filter(w => w.length > 0);
    const lowWordCount = words.length < (isPaginationLost ? (15 * totalPagesReported) : 15);

    // Decision Heuristic
    let contentType = 'text';

    if (hasImageMarkers) {
        contentType = 'image';
    } else if (isVeryShort && (hasImageKeywords || lowWordCount)) {
        // Short text with visual keywords or very few words -> Image
        contentType = 'image';
    } else if (hasImageKeywords && textLength < 800) {
        // Medium text but strongly suggests an image title (e.g. "DIAGRAMA DESPLIEGUE AWS")
        // Increased threshold to 800 to catch the user's example
        contentType = 'image';
    }

    pages.push({
      pageNumber: pageNumber,
      contentType: contentType,
      content: trimmedText,
      metadata: {
        textLength: textLength,
        wordCount: words.length,
        hasMarkers: hasImageMarkers,
        hasKeywords: hasImageKeywords,
        isPaginationLost: isPaginationLost
      }
    });
  });

  // Return the pages in the expected object structure for Split node
  outputItems.push({
    json: {
      pages: pages,
      originalMetadata: item.json.info || {},
      pdfStats: {
          reportedPages: totalPagesReported,
          extractedBlocks: rawPageTexts.length
      }
    }
  });
}

return outputItems;

