try { adjacentChunks = $input.all().map(i => i.json).filter(r => r && r.id); } catch (_) { adjacentChunks = []; }
if (initialResults.length === 0 && adjacentChunks.length === 0) {
  return [{ json: { contexto: '', images: [], sourceUrl: '', sources: [], sinResultados: true, query: input.query, user_name: input.user_name, base: input.base } }];
}
const seenContent = new Set();
const dedup = (arr) => arr.filter(r => {
  const key = (r.content || '').trim();
  if (!key || seenContent.has(key)) return false;
  seenContent.add(key);
  return true;
});
const textResults = dedup(relevantResults).filter(r => r.type === 'text');
const imageResults = dedup(relevantResults).filter(r => r.type === 'image');
const allTextChunks = [...textResults, ...dedup(adjacentChunks).filter(r => r.type === 'text')];
const grouped = {}, groupMeta = {};
for (const chunk of allTextChunks) {
  const src = chunk.metadata?.source_url || 'unknown';
  if (!grouped[src]) {
    grouped[src] = [];
    groupMeta[src] = { manual_name: chunk.metadata?.manual_name || '', article_title: chunk.metadata?.article_title || '', contextual_header: chunk.metadata?.contextual_header || '' };
  }
  grouped[src].push({ content: chunk.content, _pn: chunk.metadata?.page_number || 0, _ci: chunk.metadata?.chunk_index || 0 });
}
const contextParts = [];
for (const [src, chunks] of Object.entries(grouped)) {
  chunks.sort((a, b) => a._pn - b._pn || a._ci - b._ci);
  const meta = groupMeta[src];
  const hp = [meta.manual_name, meta.article_title, meta.contextual_header].filter(Boolean);
  const hl = hp.length > 0 ? '[' + hp.join(' > ') + ']\n' : '';
  contextParts.push(hl + chunks.map(c => c.content).join('\n'));
}
const contexto = contextParts.join('\n\n---\n\n');
const images = imageResults.map((r, i) => ({
  index: i + 1,
  image_id: r.id,
  image_url: r.metadata?.image_url || '',
  filename: r.metadata?.image_filename || ('imagen_' + (i + 1) + '.jpg'),
  source: r.metadata?.manual_name || '',
  page_number: r.metadata?.page_number || 0
})).slice(0, 4);
const sourcesMap = {};
for (const r of relevantResults) {
  const su = r.metadata?.source_url || '';
  if (!su) continue;
  if (!sourcesMap[su]) sourcesMap[su] = { source_url: su, manual_name: r.metadata?.manual_name || '', pages: new Set() };
  if (r.metadata?.page_number) sourcesMap[su].pages.add(r.metadata.page_number);
}
const sources = Object.values(sourcesMap).map(s => ({ source_url: s.source_url, manual_name: s.manual_name, pages: [...s.pages].sort((a, b) => a - b) }));
const mainSourceUrl = relevantResults[0]?.metadata?.source_url || '';
return [{ json: { contexto, images, sourceUrl: mainSourceUrl, sources, sinResultados: false, query: input.query, user_name: input.user_name, base: input.base } }];

const { contexto, images, query, user_name } = $json;
const fecha = new Date().toLocaleDateString('es-MX', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const imageList = images && images.length > 0
  ? '

IMAGENES T├ëCNICAS DISPONIBLES:
' + images.map(img => '  [' + img.index + '] ' + img.filename).join('
') + '
Para incluir imagen usa: [ENVIAR_IMAGENES: N].'
  : '';
const systemInstruction = 'FECHA ACTUAL: ' + fecha + '
Eres SARA, la asistente t├®cnica experta de Satcom. Resuelves dudas usando la documentaci├│n t├®cnica proporcionada.

INSTRUCCIONES:
1. La informaci├│n bajo DOCUMENTACION DE APOYO es tu conocimiento interno. NO agradezcas al usuario por ella.
2. Responde directamente y de forma profesional.
3. Si la respuesta no est├í en los fragmentos, ind├¡calo sin inventar.
4. Est├ís hablando con ' + (user_name || 'Usuario') + '.

FORMATO:
- Cita la fuente solo cuando provenga de la documentaci├│n.
- Usa listas con vi├▒etas para pasos t├®cnicos.
- Para im├ígenes que aporten valor: [ENVIAR_IMAGENES: N].
- NO inventes informaci├│n.';
let fullPrompt;
if (contexto) {
  fullPrompt = 'DOCUMENTACION DE APOYO (Tu base de conocimientos):
' + contexto + imageList + '

________________________________
CONSULTA DEL USUARIO:
' + query;
} else {
  fullPrompt = query;
}
return [{ json: {
  systemInstruction,
  fullPrompt,
  images: $json.images,
  sources: $json.sources,
  sourceUrl: $json.sourceUrl,
  sinResultados: $json.sinResultados,
  base: $json.base
} }];

const preparador = $('Preparar_Prompt').item.json;
const imagesFromRAG = preparador.images || [];
const sources = preparador.sources || [];
const base = preparador.base || '';
const input = $('Extraer_Plan').item.json;
let finalResponse = $json.output || '';
if (!finalResponse) finalResponse = 'No encontr├® informaci├│n relevante en la base de conocimientos. Por favor reformula tu pregunta.';
const regex = /\[ENVIAR_IMAGENES:\s*([\d,\s]+)\]/gi;
const allMatches = [...finalResponse.matchAll(regex)];
const selectedImages = [];
for (const match of allMatches) {
  const indices = match[1].split(',').map(s => parseInt(s.trim())).filter(n => !isNaN(n));
  for (const idx of indices) {
    const img = imagesFromRAG[idx - 1];
    if (img && !selectedImages.find(si => si.image_id === img.image_id)) {
      selectedImages.push({
        image_id: img.image_id,
        image_url: img.image_url,
        filename: img.filename,
        source: img.source,
        page_number: img.page_number
      });
    }
  }
}
finalResponse = finalResponse.replace(regex, '').trim();
return [{ json: {
  response: finalResponse,
  images: selectedImages,
  sources,
  meta: {
    query_type: input.queryType || 'conceptual',
    candidates_found: $('Filtrar_Candidatos').item.json.all_results?.length || 0,
    candidates_selected: $('Procesar_Seleccion').item.json.indices_utilizados?.length || 0,
    base_searched: base
  }
} }];

// ÔöÇÔöÇ PLANIFICADOR V4 ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
const input = $('input').item.json;
const fecha = new Date().toLocaleDateString('es-MX', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const prompt = `FECHA: ${fecha}\nCONSULTA: ${input.query}\n` +
  `Responde SOLO JSON: {"buscar": true, "queries": ["query expandida"], "detected_manual": "nombre-manual", "semantic_weight": 0.5, "keyword_weight": 0.5}`;

return [{ json: { plan_body: { contents: [{ role: 'user', parts: [{ text: prompt }] }], generationConfig: { responseMimeType: 'application/json' } } } }];

// ÔöÇÔöÇ PREPARAR RERANKER ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
const results = $input.all().map(i => i.json);
const query = $('input').item.json.query;
const summaries = results.map((r, i) => `[${i}] ${r.content.substring(0, 150)}`).join('\n');
const prompt = `Consulta: ${query}\nResultados:\n${summaries}\nResponde JSON: {"relevant_indices": [indices]}`;

return [{ json: { reranker_body: { contents: [{ role: 'user', parts: [{ text: prompt }] }], generationConfig: { responseMimeType: 'application/json' } }, results } }];

// ÔöÇÔöÇ FILTRAR Y PREPARAR ADJACENT ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
const indices = JSON.parse($json.candidates[0].content.parts[0].text).relevant_indices;
const allResults = $('Preparar Reranker').item.json.results;
const best = indices.map(i => allResults[i]).filter(Boolean).slice(0, 3);

return [{ json: { 
  expansionParams: { 
    p_source_urls: best.map(r => r.metadata.source_url), 
    p_page_numbers: best.map(r => r.metadata.page_number), 
    p_exclude_ids: allResults.map(r => r.id), 
    p_window: 1 
  }, 
  best 
} }];

// ÔöÇÔöÇ CONSTRUIR CONTEXTO FINAL ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
const adjacent = $input.all().map(i => i.json);
const best = $('Filtrar con IA').item.json.best;
const all = [...best, ...adjacent];

const contexto = all.map(r => `[${r.metadata?.manual_name}]\n${r.content}`).join('\n\n---\n\n');
return [{ json: { contexto, sourceUrl: best[0]?.metadata?.source_url, query: $('input').item.json.query } }];

