const items = $('ChatHistory').all();
//$input.all();
let chatFormateado = "";
let ultimaFechaRef = "";

if (items.length === 0) {
    return { historialLectura: "Sin Historial" };
}

// --- L├ôGICA DE FILTRADO POR REINICIO ---
// Busca el ├║ltimo evento donde se limpiaron los datos para ignorar lo anterior
let startIndex = 0;
for (let i = items.length - 1; i >= 0; i--) {
    const texto = (items[i].json.texto || "").toLowerCase();
    if (texto.includes("reinicio") || texto.includes("eliminado") || texto.includes("borrado")) {
        startIndex = i + 1; 
        break;
    }
}
const itemsFiltrados = items.slice(startIndex);

function obtenerEtiquetaFecha(objFecha) {
    return objFecha.toLocaleDateString('es-EC', { 
        weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
    }).toUpperCase();
}

// --- SEPARADOR INICIAL ---
const fechaInicialValida = itemsFiltrados.length > 0 && itemsFiltrados[0].json.fecha ? new Date(itemsFiltrados[0].json.fecha) : new Date();
chatFormateado += `ÔòöÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòù\n`;
chatFormateado += `    INICIO DEL HISTORIAL RELEVANTE - ${obtenerEtiquetaFecha(fechaInicialValida)}\n`;
chatFormateado += `ÔòÜÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòØ\n\n`;

for (const item of itemsFiltrados) {
    const msg = item.json;
    const rolSeguro = (msg.rol || "Asistente").toString().toLowerCase();
    const textoSeguro = msg.texto || "[Mensaje sin contenido]";
    const fechaSegura = msg.fecha ? new Date(msg.fecha) : new Date();

    // Detecci├│n de cambio de d├¡a
    const fechaActualRef = fechaSegura.toDateString();
    if (fechaActualRef !== ultimaFechaRef && ultimaFechaRef !== "") {
        chatFormateado += `\n­ƒôà ÔöÇÔöÇÔöÇÔöÇ ${obtenerEtiquetaFecha(fechaSegura)} ÔöÇÔöÇÔöÇÔöÇ ­ƒôà\n\n`;
    }
    ultimaFechaRef = fechaActualRef;

    // Formateo de hora
    const hora = fechaSegura.toLocaleTimeString('es-EC', { hour: '2-digit', minute: '2-digit', hour12: true });

    // --- MAPEO DE ROLES ACTUALIZADO ---
    let icono = "­ƒñû";
    let etiqueta = "SOPORTE";

    if (rolSeguro === 'usuario') {
        icono = "­ƒæñ";
        etiqueta = "Usuario";
    } else if (rolSeguro === 'agentehumano') {
        icono = "­ƒæ¿ÔÇì­ƒÆ╝"; // Cambio: Icono para agente humano (L2)
        etiqueta = "ANALISTA L2 (HUMANO)"; // Cambio: Etiqueta para diferenciar de la IA
    } else if (rolSeguro === 'agenteia') {
        icono = "­ƒñû";
