      const currentHora = new Date(data.Hora).getTime();

      // 5. L├│gica de "El m├ís reciente":
      // Comparamos la hora del objeto actual contra la guardada en el mapa
      if (!latestChatsMap[chatId] || currentHora > new Date(latestChatsMap[chatId].Hora).getTime()) {
        latestChatsMap[chatId] = data;
      }
    } catch (error) {
      // Si el string no es un JSON v├ílido, lo saltamos
      continue;
    }
  }
}

