return { html };

// 1. Obtenemos todos los items de entrada
const items = $input.all();

// 2. Usaremos un objeto para rastrear el registro m├ís reciente por cada chat_id
const latestChatsMap = {};

// 3. Iteramos por cada item principal
for (const item of items) {
  const estadoChats = item.json.EstadoChats;

  if (!estadoChats || !Array.isArray(estadoChats)) continue;

  // 4. Iteramos por cada string JSON dentro de EstadoChats
  for (const chatString of estadoChats) {
    try {
      // Parseamos el string (ahora devuelve directamente el objeto, no un array)
      const data = JSON.parse(chatString);

      const chatId = data.chat_id;
      if (!chatId) continue; // Seguridad por si el objeto est├í vac├¡o

      const currentHora = new Date(data.Hora).getTime();

      // 5. L├│gica de "El m├ís reciente":
      // Comparamos la hora del objeto actual contra la guardada en el mapa
      if (!latestChatsMap[chatId] || currentHora > new Date(latestChatsMap[chatId].Hora).getTime()) {
        latestChatsMap[chatId] = data;
      }
    } catch (error) {
      // Si el string no es un JSON v├ílido, lo saltamos
      continue;
    }
  }
}

// 6. Convertimos nuestro mapa de resultados al formato de salida de n8n
return Object.values(latestChatsMap).map(chat => ({ json: chat }));

const memoryResult = $('Fetch Memory').all().map(item => item.json);
// History comes DESC, reverse to make it ASC
const history = memoryResult.reverse();

return [{
  json: {
    ...$('Webhook').item.json,
    chatHistory: history
  }
}];

// Resultados de match_zoho_learn_vectors_v3
const results = $input.all().map(i => i.json);
const query = $('Webhook').item.json.body.query;
const sessionId = $('Webhook').item.json.body.sessionId;

if (!results || results.length === 0) {
  return [{
    json: {
      contexto: '',
      images: [],
      sourceUrl: '',
      sourceName: '',
      pregunta: query,
      chat_id: sessionId,
      sinResultados: True
    }
  }];
}

const textChunks = results.filter(r => r.type === 'text').slice(0, 7).map(r => r.content);
const imageResults = results.filter(r => r.type === 'image');
const images = imageResults.map((r, i) => ({
  index: i + 1,
  filename: r.metadata?.image_filename || `imagen_${i+1}.jpg`,
  imageUrl: r.metadata?.image_url || null,
  base64: r.metadata?.original_content || null,
  sourceUrl: r.metadata?.source_url || '',
  rrf_score: r.rrf_score
})).filter(img => img.imageUrl || img.base64).slice(0, 6);

const sourceUrl = results[0]?.metadata?.source_url || '';
const sourceName = results[0]?.metadata?.source || '';

return [{
  json: {
    contexto: textChunks.join('\n\n---\n\n'),
    images,
    sourceUrl,
    sourceName,
    pregunta: query,
    chat_id: sessionId,
    sinResultados: False,
    totalResultados: results.length
  }
}];

const { contexto, images, pregunta, sourceUrl, sourceName, sinResultados, chat_id } = $json;
const history = $('Format Memory').item.json.chatHistory || [];

if (sinResultados || !contexto) {
  return [{
    json: {
      gemini_body: null,
      images: [],
      sourceUrl: '',
      sourceLink: '',
      chat_id,
      pregunta,
      sinResultados: True
    }
  }];
}

let imageContext = '';
if (images.length > 0) {
  imageContext = '\n\nIMAGENES DISPONIBLES EN EL MANUAL:\n' +
    images.map(img => `[Imagen ${img.index}]: ${img.filename}`).join('\n') +
    '\n\nSi una imagen aporta valor a tu respuesta, incluye el tag [ENVIAR_IMAGENES: N] (ej: [ENVIAR_IMAGENES: 1]).';
}

const systemInstruction = `Eres SARA, el asistente de Inteligencia Artificial para el sistema. \nResponde UNICAMENTE basandote en el contexto del manual proporcionado.\nSi no encuentras la respuesta en el contexto, dilo claramente y sugiere contactar soporte.\nSe conciso, directo y usa listas cuando sea apropiado.\nResponde en el mismo idioma que la pregunta del usuario.`;

const cleanSourceUrl = sourceUrl?.endsWith('?') ? sourceUrl.slice(0, -1) : (sourceUrl || '');
const sourceLink = cleanSourceUrl ? `\n\n­ƒôû [Ver en el manual original](${cleanSourceUrl})` : '';

const userMessage = `CONTEXTO DEL MANUAL:\n${contexto}${imageContext}\n\nPREGUNTA DEL USUARIO: ${pregunta}`;

// Convert history to Gemini parts
let contents = [];
for (const msg of history) {
    if(!msg.content) continue;
    contents.push({
        role: msg.role === 'assistant' ? 'model' : 'user',
        parts: [{ text: msg.content }]
    });
}
contents.push({ role: 'user', parts: [{ text: userMessage }] });

const geminiBody = {
  system_instruction: { parts: [{ text: systemInstruction }] },
  contents,
  generationConfig: { temperature: 0.1, maxOutputTokens: 2048 }
};

return [{
  json: {
    gemini_body: geminiBody,
    images,
    sourceUrl: cleanSourceUrl,
    sourceLink,
    chat_id,
    pregunta,
    sinResultados: False
  }
}];

const { images, sourceUrl, sourceLink, chat_id, sinResultados } = $('Preparar Body LLM').item.json;

if (sinResultados) {
  return [{
    json: {
      final_response: 'No encontr├® informaci├│n relevante en los manuales para tu consulta. Por favor, intenta reformular la pregunta o contacta a soporte.',
      send_image: False,
      image_url: null,
      chat_id
    }
  }];
}

const candidates = $json.candidates;

if (!candidates || candidates.length === 0) {
  return [{
    json: {
      final_response: 'Hubo un problema al procesar tu consulta. Por favor, intenta de nuevo.',
      send_image: False,
      image_url: null,
      chat_id
    }
  }];
}

let responseText = candidates[0]?.content?.parts?.[0]?.text || '';
const imageTagMatch = responseText.match(/\[ENVIAR_IMAGENES:\s*([\d,\s]+)\]/i);
let selectedImage = null;

if (imageTagMatch && images.length > 0) {
  const indices = imageTagMatch[1].split(',').map(n => parseInt(n.trim()) - 1);
  const validIdx = indices.find(idx => idx >= 0 && idx < images.length && (images[idx].imageUrl || images[idx].base64));
  if (validIdx !== undefined) {
    selectedImage = images[validIdx];
  }
}

responseText = responseText.replace(/\[ENVIAR_IMAGENES:[\d,\s]+\]/gi, '').trim();

if (sourceLink) {
  responseText += sourceLink;
}

return [{
  json: {
    final_response: responseText,
    send_image: selectedImage !== null,
    image_url: selectedImage?.imageUrl || null,
    image_base64: selectedImage?.base64 || null,
    chat_id,
    sourceUrl
  }
}];

