const token = $item("0").$node["Variables"].json["TokenZoho"];
const orgId = $item("0").$node["Variables"].json["Organization_id"];

let fromIndex = 0;
const limit = 100;
let buscarPaginas = true;

try {
  while (buscarPaginas) {
    const urlList = `https://desk.zoho.com/api/v1/contacts?limit=${limit}&from=${fromIndex}`;

    // 1. Buscamos al contacto
    const resList = await this.helpers.httpRequest({
      method: "GET", url: urlList,
      headers: { "Authorization": "Zoho-oauthtoken " + token, "orgId": orgId },
      json: true
    });

    let contactsArray = [];
    if (Array.isArray(resList)) contactsArray = resList;
    else if (resList && Array.isArray(resList.data)) contactsArray = resList.data;
    else {
       if (fromIndex === 0) return [{ json: { found: false, message: "Respuesta vac├¡a" } }];
       break; 
    }

    if (contactsArray.length === 0) break;

    const found = contactsArray.find(contacto => JSON.stringify(contacto).toLowerCase().includes(textoABuscar));

    if (found) {
        // LO ENCONTRAMOS. 
        try {
            // 2. Traemos las empresas a las que pertenece
            const urlAccounts = `https://desk.zoho.com/api/v1/contacts/${found.id}/accounts`;
            const resAccounts = await this.helpers.httpRequest({
                method: "GET", url: urlAccounts,
                headers: { "Authorization": "Zoho-oauthtoken " + token, "orgId": orgId },
                json: true
            });

            if (resAccounts.data) {
                // 3. MAGIA NUEVA: Por cada empresa, vamos a buscar su perfil completo para sacar el Pa├¡s
                for (let i = 0; i < resAccounts.data.length; i++) {
                    const empresaBasica = resAccounts.data[i];
                    try {
                        const urlSolaEmpresa = `https://desk.zoho.com/api/v1/accounts/${empresaBasica.id}`;
                        const detalleEmpresa = await this.helpers.httpRequest({
                            method: "GET", url: urlSolaEmpresa,
                            headers: { "Authorization": "Zoho-oauthtoken " + token, "orgId": orgId },
                            json: true
                        });
                        // Le pegamos el pa├¡s a nuestro arreglo local
                        empresaBasica.country = detalleEmpresa.country || "Desconocido";
                    } catch (errCuenta) {
                        empresaBasica.country = "Error obteniendo pa├¡s";
                    }
                }
                found.empresasAsociadas = resAccounts.data;
            }
        } catch (accError) {
            found.empresasAsociadas = "Error al intentar obtener las cuentas: " + accError.message;
        }

        return [{ json: { found: true, contact: found, matchMethod: "Paginated General Search" } }];
    }

    if (contactsArray.length < limit) buscarPaginas = false;
    else fromIndex += limit;
  }

  return [{ json: { found: false, message: "Ning├║n contacto contiene este texto." } }];

} catch (error) {
  return [{ json: { found: false, error: true, message: error.message } }];
}

